#!/usr/bin/env python3
import json, os, sys, traceback, time
import requests

def load_config():
    path = "/run/connector.json"
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)
    auth = data.get("auth", {}) or {}
    cfg = data.get("configuration", {}) or {}
    return auth, cfg

def build_jql(cfg):
    if cfg.get("jql"):
        return cfg["jql"]
    parts = []
    assignee = cfg.get("assignee")
    if not assignee:
        raise ValueError("configuration.assignee is required when configuration.jql is not provided")
    s = str(assignee).strip()
    if s.lower().startswith("accountid:"):
        accid = s.split(":", 1)[1].strip().strip('"')
        parts.append(f'assignee in (accountId("{accid}"))')
    else:
        parts.append(f'assignee = "{s}"')
    project = cfg.get("projectKey")
    if project:
        parts.append(f'project = "{project}"')
    if not cfg.get("includeClosed", False):
        parts.append('resolution = Unresolved')
    if not cfg.get("includeSubtasks", True):
        parts.append('issuetype not in subTaskIssueTypes()')
    return " AND ".join(parts) + " order by updated DESC"

def request_with_retries(method, url, **kwargs):
    retries = 3
    last = None
    for attempt in range(1, retries + 1):
        try:
            resp = requests.request(method, url, **kwargs)
        except Exception:
            last = Exception(f"HTTP request failed on attempt {attempt}")
            time.sleep(min(2 ** attempt, 10))
            continue
        if resp.status_code == 429:
            ra = resp.headers.get("Retry-After")
            try:
                delay = float(ra) if ra else min(2 ** attempt, 30)
            except Exception:
                delay = min(2 ** attempt, 30)
            time.sleep(delay)
            last = resp
            continue
        if 500 <= resp.status_code < 600:
            time.sleep(min(2 ** attempt, 10))
            last = resp
            continue
        return resp
    if last is None:
        raise RuntimeError("HTTP request failed and no response captured")
    if isinstance(last, requests.Response):
        return last
    raise RuntimeError(str(last))

def _split_to_list(value):
    if not value:
        return None
    if isinstance(value, list):
        return [str(v).strip() for v in value if str(v).strip()]
    if isinstance(value, str):
        v = value.strip()
        if not v:
            return None
        try:
            parsed = json.loads(v)
            if isinstance(parsed, list):
                return [str(x).strip() for x in parsed if str(x).strip()]
        except Exception:
            pass
        return [part.strip() for part in v.split(",") if part.strip()]
    return None

def _make_payload(payload_key, jql, start_at, page_size, fields_list, expand_list, include_expand=True):
    payload = {
        payload_key: jql,
        "startAt": start_at,
        "maxResults": page_size,
    }
    if fields_list:
        payload["fields"] = fields_list
    if include_expand and expand_list:
        payload["expand"] = expand_list
    return payload

def _contains_any(msgs, substrs):
    if not msgs:
        return False
    all_msgs = []
    if isinstance(msgs, dict):
        # sometimes Jira returns {'errorMessages': ['...']}
        msgs = msgs.get("errorMessages") or []
    if isinstance(msgs, list):
        all_msgs = [str(m).lower() for m in msgs]
    else:
        all_msgs = [str(msgs).lower()]
    for s in substrs:
        s = s.lower()
        if any(s in m for m in all_msgs):
            return True
    return False

def main():
    try:
        auth, cfg = load_config()
        base_url = (auth.get("baseUrl") or os.environ.get("AUTH_BASEURL") or "").strip().rstrip("/")
        email = (auth.get("email") or os.environ.get("AUTH_EMAIL") or "").strip()
        api_token = (auth.get("apiToken") or os.environ.get("AUTH_APITOKEN") or "").strip()
        if not base_url or not email or not api_token:
            raise ValueError("Missing Jira credentials: auth.baseUrl, auth.email, and auth.apiToken are required")

        jql = build_jql(cfg)
        headers = {
            "Accept": "application/json",
            "Content-Type": "application/json"
        }
        auth_tuple = (email, api_token)

        start_at = int(cfg.get("startAt", 0) or 0)
        page_size = int(cfg.get("maxResults", 50) or 50)
        if page_size > 100:
            page_size = 100
        total_limit = int(cfg.get("limit", 0) or 0)

        fields_val = (cfg.get("fields") or "").strip() if isinstance(cfg.get("fields"), str) else cfg.get("fields")
        expand_val = (cfg.get("expand") or "").strip() if isinstance(cfg.get("expand"), str) else cfg.get("expand")
        fields_list = _split_to_list(fields_val)
        expand_list = _split_to_list(expand_val)

        # Prefer the new Jira endpoint; keep fallbacks for compatibility
        endpoints = [
            ("POST", f"{base_url}/rest/api/3/search/jql"),
            ("POST", f"{base_url}/rest/api/3/search"),
            ("GET", f"{base_url}/rest/api/3/search/jql"),
            ("GET", f"{base_url}/rest/api/3/search"),
        ]

        chosen = None  # (method, url, payload_key)
        first_page_data = None
        used_payload_key = "jql"  # default for POST bodies
        last_error = None

        # Probe endpoints to find one that works for first page
        for method, url in endpoints:
            try:
                if method == "POST":
                    # Try with 'jql' key first
                    payload = _make_payload("jql", jql, start_at, page_size, fields_list, expand_list, include_expand=True)
                    resp = request_with_retries("POST", url, json=payload, auth=auth_tuple, headers=headers, timeout=30)

                    if resp.status_code == 200:
                        chosen = (method, url, "jql")
                        first_page_data = resp.json()
                        break

                    # Handle common errors and retry strategies
                    try:
                        err_json = resp.json()
                    except Exception:
                        err_json = {"text": resp.text}

                    # If expand rejected, retry without expand
                    if _contains_any(err_json.get("errorMessages"), ["expand"]):
                        payload_no_expand = _make_payload("jql", jql, start_at, page_size, fields_list, expand_list, include_expand=False)
                        resp2 = request_with_retries("POST", url, json=payload_no_expand, auth=auth_tuple, headers=headers, timeout=30)
                        if resp2.status_code == 200:
                            chosen = (method, url, "jql")
                            first_page_data = resp2.json()
                            break
                        else:
                            try:
                                err_json = resp2.json()
                            except Exception:
                                err_json = {"text": resp2.text}

                    # If server doesn't recognize 'jql' field, try 'query'
                    if _contains_any(err_json.get("errorMessages"), ["unrecognized field \"jql\"", "provide 'query'", "either 'query' or 'queries'"]):
                        payload_q = _make_payload("query", jql, start_at, page_size, fields_list, expand_list, include_expand=True)
                        resp3 = request_with_retries("POST", url, json=payload_q, auth=auth_tuple, headers=headers, timeout=30)
                        if resp3.status_code == 200:
                            chosen = (method, url, "query")
                            first_page_data = resp3.json()
                            break
                        else:
                            try:
                                err_json = resp3.json()
                            except Exception:
                                err_json = {"text": resp3.text}

                    # If endpoint is gone or method not allowed, try next
                    if resp.status_code in (404, 405, 410):
                        last_error = f"{resp.status_code} - {err_json}"
                        continue

                    last_error = f"{resp.status_code} - {err_json}"

                else:  # GET
                    # Build query params for GET; 'fields' and 'expand' must be comma-separated strings
                    params = {
                        "jql": jql,
                        "startAt": start_at,
                        "maxResults": page_size,
                    }
                    if fields_list:
                        params["fields"] = ",".join(fields_list)
                    if expand_list:
                        params["expand"] = ",".join(expand_list)

                    resp = request_with_retries("GET", url, params=params, auth=auth_tuple, headers=headers, timeout=30)
                    if resp.status_code == 200:
                        chosen = (method, url, None)
                        first_page_data = resp.json()
                        break
                    else:
                        try:
                            err_json = resp.json()
                        except Exception:
                            err_json = {"text": resp.text}
                        # If GET not supported or endpoint gone, try next
                        if resp.status_code in (404, 405, 410):
                            last_error = f"{resp.status_code} - {err_json}"
                            continue
                        last_error = f"{resp.status_code} - {err_json}"
            except Exception as e:
                last_error = str(e)
                continue

        if not chosen:
            raise RuntimeError(f"Jira API error: could not find a working search endpoint. Last error: {last_error}")

        method, url, payload_key = chosen
        all_issues = []
        fetched = 0
        total_available = None

        # Process first page data
        if first_page_data is not None:
            total_available = first_page_data.get("total")
            issues = first_page_data.get("issues", [])
            for issue in issues:
                all_issues.append(issue)
                fetched += 1
                if total_limit and fetched >= total_limit:
                    break
            start_at += len(issues)

        # Continue pagination
        while (not total_limit or fetched < total_limit) and (total_available is None or start_at < total_available):
            if method == "POST":
                payload = _make_payload(payload_key or "jql", jql, start_at, page_size, fields_list, expand_list, include_expand=True)
                resp = request_with_retries("POST", url, json=payload, auth=auth_tuple, headers=headers, timeout=30)
                if resp.status_code != 200:
                    try:
                        err_json = resp.json()
                    except Exception:
                        err_json = {"text": resp.text}
                    # Retry once without expand if expand is problematic
                    if _contains_any(err_json.get("errorMessages"), ["expand"]):
                        payload_no_expand = _make_payload(payload_key or "jql", jql, start_at, page_size, fields_list, expand_list, include_expand=False)
                        resp2 = request_with_retries("POST", url, json=payload_no_expand, auth=auth_tuple, headers=headers, timeout=30)
                        if resp2.status_code == 200:
                            resp = resp2
                        else:
                            try:
                                err_json = resp2.json()
                            except Exception:
                                err_json = {"text": resp2.text}
                            raise RuntimeError(f"Jira API error: {resp2.status_code} - {err_json}")
                    else:
                        raise RuntimeError(f"Jira API error: {resp.status_code} - {err_json}")
            else:
                params = {
                    "jql": jql,
                    "startAt": start_at,
                    "maxResults": page_size,
                }
                if fields_list:
                    params["fields"] = ",".join(fields_list)
                if expand_list:
                    params["expand"] = ",".join(expand_list)
                resp = request_with_retries("GET", url, params=params, auth=auth_tuple, headers=headers, timeout=30)
                if resp.status_code != 200:
                    try:
                        err_json = resp.json()
                    except Exception:
                        err_json = {"text": resp.text}
                    raise RuntimeError(f"Jira API error: {resp.status_code} - {err_json}")

            data = resp.json()
            total_available = data.get("total", total_available)
            issues = data.get("issues", [])
            if not issues:
                break
            for issue in issues:
                all_issues.append(issue)
                fetched += 1
                if total_limit and fetched >= total_limit:
                    break
            if total_limit and fetched >= total_limit:
                break
            start_at += len(issues)
            if total_available is not None and start_at >= total_available:
                break

        result = {"ok": True, "jql_used": jql, "count": len(all_issues), "issues": all_issues}
        print(json.dumps(result, ensure_ascii=False))
    except Exception as e:
        err = {"ok": False, "error": str(e), "traceback": traceback.format_exc()}
        print(json.dumps(err, ensure_ascii=False))
        try:
            sys.stderr.write(err["traceback"] + "\n")
        except Exception:
            pass
        sys.exit(1)

if __name__ == "__main__":
    main()
